507   Type *Ty = X->getType();
508   if (!Ty->isIntegerTy())
509     return false;
510 
511   bool IsIntMinPoison = cast<ConstantInt>(II->getArgOperand(1))->isOne();
512   APInt IntMin = APInt::getSignedMinValue(Ty->getScalarSizeInBits());
